SELECT

FROM tb_work_unit wu
WHERE wu.mbr_acct_idx = #{req.mbrAcctIdx}
  AND wu.del_at IS NULL

    AND wu.ttl LIKE CONCAT('%', #{req.kwd}, '%')


    AND wu.ctgr = #{req.ctgr}


    AND wu.sts = #{req.sts}


    AND wu.use_yn = #{req.useYn}

ORDER BY ${req.orderByClause}

SELECT

FROM tb_wrk_unit_git_cfg
WHERE work_unit_idx = #{workUnitIdx}
  AND mbr_acct_idx = #{mbrAcctIdx}
  AND del_at IS NULL
ORDER BY created_at ASC

SELECT EXISTS ( SELECT 1 FROM tb_work_unit WHERE mbr_acct_idx = #{mbrAcctIdx} AND lower(trim(ttl)) = lower(trim(#{ttl})) AND del_at IS NULL
AND work_unit_uuid != CAST(#{excludeUuid} AS UUID)
)
